SELECT * FROM (
    SELECT T.*, ROWNUM RN FROM (
        SELECT id, name, price, stock, category_id, category, status, created_at, updated_at
        FROM products

            is_deleted = 0

                AND (name LIKE '%' || #{keyword} || '%' OR description LIKE '%' || #{keyword} || '%')

            AND category_id = #{categoryId}
            AND category = #{category}
            AND status = #{status}

        ORDER BY created_at DESC
    ) T WHERE ROWNUM <= #{offset} + #{size}
) WHERE RN > #{offset}

SELECT COUNT(*) FROM products

    is_deleted = 0

        AND (name LIKE '%' || #{keyword} || '%' OR description LIKE '%' || #{keyword} || '%')

    AND category_id = #{categoryId}
    AND category = #{category}
    AND status = #{status}

