UPDATE products
name = #{name}, description = #{description}, price = #{price}, stock = #{stock}, category_id = #{categoryId}, category = #{category}, image_url = #{imageUrl}, status = #{status}, updated_at = SYSTIMESTAMP, updated_by = #{updatedBy}
WHERE id = #{id} AND updated_at = #{updatedAt}

UPDATE products
SET is_deleted = 1, updated_at = SYSTIMESTAMP, updated_by = #{updatedBy}
WHERE id = #{id} AND updated_at = #{updatedAt}

UPDATE products
SET status = #{status},
    updated_at = SYSTIMESTAMP,
    updated_by = #{updatedBy}
WHERE id = #{id} AND updated_at = #{updatedAt}
